"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { useExperienceViewport, useFinePointer, usePrefersReducedMotion } from "@/components/experience/experience-runtime";

export type ImageTrailProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  /** Image sources cycled along the trail. */
  images: string[];
  children?: React.ReactNode;
  /** Rendered instead of the trail on touch / reduced-motion. */
  fallback?: React.ReactNode;
  /** Card width in pixels. */
  size?: number;
  /** Pointer distance in pixels between two spawned cards. */
  threshold?: number;
  /** Lifetime of one card in milliseconds. */
  lifeMs?: number;
  /** Number of pooled cards (the visual trail length). */
  maxActive?: number;
  /** Random rotation jitter in degrees. */
  rotationJitter?: number;
  imageClassName?: string;
};

/**
 * An editorial pointer trail: moving the cursor scatters a decaying trail of
 * image cards behind it. Content stays in `children`; the trail is decorative.
 */
export function ImageTrail({
  children,
  className,
  fallback,
  imageClassName,
  images,
  label,
  lifeMs = 1000,
  maxActive = 8,
  rotationJitter = 14,
  size = 180,
  threshold = 96,
  ...props
}: ImageTrailProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const poolRef = React.useRef<Array<HTMLDivElement | null>>([]);
  const stateRef = React.useRef({ lastX: 0, lastY: 0, distance: 0, slot: 0, image: 0, primed: false });
  const reducedMotion = usePrefersReducedMotion();
  const finePointer = useFinePointer();
  const viewport = useExperienceViewport();
  const active = finePointer && !reducedMotion && images.length > 0 && viewport !== "mobile";
  const activeSize = size * (viewport === "tablet" ? 0.78 : 1);
  const activeThreshold = threshold * (viewport === "tablet" ? 1.18 : 1);
  const activeLifeMs = lifeMs * (viewport === "tablet" ? 0.82 : 1);
  const activeMax = Math.min(maxActive, viewport === "tablet" ? 5 : maxActive);

  React.useEffect(() => {
    if (!active) return;
    const loaders = images.map((src) => {
      const image = new Image();
      image.decoding = "async";
      image.src = src;
      return image;
    });
    return () => {
      loaders.forEach((image) => {
        image.src = "";
      });
    };
  }, [active, images]);

  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => {
    if (!active || event.pointerType === "touch") return;
    const root = rootRef.current;
    if (!root) return;
    const rect = root.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const state = stateRef.current;
    if (!state.primed) {
      state.primed = true;
      state.lastX = x;
      state.lastY = y;
      return;
    }
    state.distance += Math.hypot(x - state.lastX, y - state.lastY);
    state.lastX = x;
    state.lastY = y;
    if (state.distance < activeThreshold) return;
    state.distance = 0;

    const card = poolRef.current[state.slot];
    state.slot = (state.slot + 1) % Math.max(1, activeMax);
    if (!card) return;
    const img = card.firstElementChild as HTMLImageElement | null;
    if (img) {
      img.src = images[state.image % images.length]!;
      state.image += 1;
    }
    const rotation = (Math.random() - 0.5) * 2 * rotationJitter;
    card.style.left = `${x}px`;
    card.style.top = `${y}px`;
    card.getAnimations().forEach((animation) => animation.cancel());
    card.animate(
      [
        { opacity: 0, transform: `translate(-50%, -50%) scale(0.55) rotate(${rotation * 1.6}deg)` },
        { opacity: 1, transform: `translate(-50%, -50%) scale(1) rotate(${rotation}deg)`, offset: 0.18 },
        { opacity: 1, transform: `translate(-50%, -46%) scale(1) rotate(${rotation}deg)`, offset: 0.62 },
        { opacity: 0, transform: `translate(-50%, -38%) scale(0.92) rotate(${rotation * 0.6}deg)` },
      ],
      { duration: activeLifeMs, easing: "cubic-bezier(0.22, 0.61, 0.36, 1)", fill: "forwards" },
    );
  };

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-image-trail
      data-experience-viewport={viewport}
      data-static={!active || undefined}
      className={cn("relative isolate overflow-hidden", className)}
      onPointerMove={handlePointerMove}
      onPointerLeave={() => {
        stateRef.current.primed = false;
        stateRef.current.distance = 0;
      }}
      {...props}
    >
      {active ? (
        <div aria-hidden className="pointer-events-none absolute inset-0 -z-10">
          {Array.from({ length: Math.max(1, activeMax) }, (_, index) => (
            <div
              key={index}
              ref={(node) => {
                poolRef.current[index] = node;
              }}
              className="absolute opacity-0 will-change-transform"
              style={{ width: activeSize }}
            >
              {/* eslint-disable-next-line @next/next/no-img-element -- registry source stays framework-neutral. */}
              <img alt="" draggable={false} className={cn("aspect-[4/5] w-full rounded-xl object-cover shadow-2xl", imageClassName)} />
            </div>
          ))}
        </div>
      ) : (
        fallback && <div className="absolute inset-0 -z-10">{fallback}</div>
      )}
      {children}
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
